/// <summary>
/// Scoped service that tracks the latest low-stock alert count for the
/// current user's selected warehouse.  Fires <see cref="OnAlertCountChanged"/>
/// so every subscribed component re-renders — not just the one that polled.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _rng = Random.Shared;

    public int LatestCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>Simulates a database query — returns a random 0-15 count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate I/O latency + random result.
        return Task.FromResult(_rng.Next(0, 16));
    }

    /// <summary>
    /// Called by whichever component owns the polling loop.
    /// Stores the count and notifies all subscribers.
    /// </summary>
    public void UpdateCount(int count)
    {
        LatestCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

