@using sv_4e55745cae7a4f709c67d2ba518d4076.Services
@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource

<select class="form-select form-select-sm" style="width:auto;"
        value="@_selectedId" @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseInfo.All)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _selectedId = WarehouseInfo.Default.Id;

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
            _selectedId = Warehouse.Id;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? WarehouseInfo.Default.Id;
        var wh = WarehouseInfo.All.FirstOrDefault(w => w.Id == id) ?? WarehouseInfo.Default;
        _selectedId = wh.Id;
        await WarehouseSource.NotifyChangedAsync(wh);
    }
}

@using sv_4e55745cae7a4f709c67d2ba518d4076.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="badge rounded-pill @BadgeClass">@AlertService.LatestCount</span>

@code {
    private Action? _handler;

    private string BadgeClass => AlertService.LatestCount > 5
        ? "text-bg-danger" : "text-bg-warning";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

