@using sv_4e55745cae7a4f709c67d2ba518d4076.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard — @(Warehouse?.Name ?? "Loading…")</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(AlertService.LatestCount > 5 ? "border-danger" : "border-warning")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4">@AlertService.LatestCount</p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Status</h5>
                <p>Monitoring <strong>@(Warehouse?.Name ?? "—")</strong> (ID: @(Warehouse?.Id ?? "—"))</p>
                <p>Polling every 10 seconds. Last check: @_lastPoll.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private CancellationTokenSource? _cts;
    private Action? _handler;
    private DateTime _lastPoll = DateTime.Now;
    private string _activeWarehouseId = string.Empty;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    protected override void OnParametersSet()
    {
        var currentId = Warehouse?.Id ?? WarehouseInfo.Default.Id;

        if (currentId != _activeWarehouseId)
        {
            _activeWarehouseId = currentId;
            RestartPolling();
        }
    }

    private void RestartPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every 10 s.
        while (!ct.IsCancellationRequested)
        {
            try
            {
                var count = await AlertService.GetLowStockCountAsync(_activeWarehouseId);
                _lastPoll = DateTime.Now;
                // UpdateCount fires OnAlertCountChanged → all subscribers re-render.
                AlertService.UpdateCount(count);
            }
            catch (ObjectDisposedException)
            {
                break;
            }

            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

